{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式発足を承認し、本日をもってキックオフとする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "移行方式は段階的に拠点をグループ分けして切り替えていく方針で確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標日を2026年5月15日から9月末から変更し、新たに2026年10月15日に設定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証・マスタ配信方式はサクラ商事さんとの共同利用（第3案）を決定し、回答書を準備して進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "週次定例会議として毎週水曜日の10時に開催する（月末の週は代理出席可）と決定する。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
